#include<bits/stdc++.h>
using namespace std;
int a[10000001];
int f(int x) {
	if(x==1){
		return 0;
	}else if(a[x]!=0){
		return a[x];
	}else if(x%2==0){
		return a[x]=min(f(x/2),f(x-1))+1;
	}else{
		return a[x]=f(x-1)+1;
	}
}
int main() {
	int n;
	cin >> n;
	cout << f(n);

	return 0;
}
